  L.worked.tokens.forEach(function(t){ var c=el('span','tok'); c.innerHTML='<span class="w" style="background:'+famHex(t.fam,.16)+';border:1px solid '+famBorder(t.fam)+'">'+t.w+'</span><span class="r">'+t.role+'</span>'; tk.appendChild(c); });
  w.appendChild(tk); if(L.worked.note)w.appendChild(el('p','note',L.worked.note)); v.appendChild(w);
