  GT_ROOT.setAttribute("style", "position:fixed;inset:0;z-index:2147483000;overflow:auto;-webkit-overflow-scrolling:touch;background:#080706;");
  GT_SR = GT_ROOT.attachShadow({ mode: "open" });
  var st = document.createElement("style"); st.textContent = GT_CSS; GT_SR.appendChild(st);
  var close = document.createElement("button"); close.className = "gt-close"; close.setAttribute("aria-label", "Κλείσιμο"); close.innerHTML = "&times;"; close.onclick = gtClose; GT_SR.appendChild(close);
  var wrap = document.createElement("div"); wrap.className = "gt-wrap";
  GT_APP = document.createElement("div"); GT_APP.id = "app"; GT_APP.className = "app"; wrap.appendChild(GT_APP);
  GT_SR.appendChild(wrap);
  document.body.appendChild(GT_ROOT);
  try { _gtPrevOverflow = document.body.style.overflow; document.body.style.overflow = "hidden"; } catch (_) {}
  document.addEventListener("keydown", gtEsc);
